/**
 * Bouton radio individuel.
 *
 * Conçu pour vivre à l'intérieur d'un `<pf-radio-group>` qui orchestre la
 * sélection. Si utilisé seul (sans groupe parent), le composant fonctionne
 * en autonome via [checked] / (checkedChange) + [name] manuel.
 */
let PfRadioComponent = class PfRadioComponent {
    constructor() {
        this.label = '';
        this.hint = '';
        this.value = '';
        this.checked = false;
        this.disabled = false;
        this.name = '';
        this.id = '';
        this.checkedChange = new EventEmitter();
        this.group = inject(PfRadioGroupComponent, { optional: true, host: true });
        this.autoId = `pf-radio-${++nextUid}`;
    }
    get inputId() {
        return this.id || this.autoId;
    }
    get hintId() {
        return this.hint ? `${this.inputId}-hint` : null;
    }
    get effectiveName() {
        return this.group?.groupName || this.name || '';
    }
    get effectiveChecked() {
        return this.group ? this.group.value === this.value : this.checked;
    }
    get effectiveDisabled() {
        return this.disabled || Boolean(this.group?.disabled);
    }
    get effectiveInvalid() {
        return Boolean(this.group?.invalid);
    }
    onChange(event) {
        const target = event.target;
        if (target.checked) {
            if (this.group) {
                this.group.selectValue(this.value);
            }
            else {
                this.checked = true;
                this.checkedChange.emit(true);
            }
        }
    }
