        label: [{ type: Input }],
        hint: [{ type: Input }],
        value: [{ type: Input }],
        checked: [{ type: Input }],
        disabled: [{ type: Input }],
        name: [{ type: Input }],
        id: [{ type: Input }],
        checkedChange: [{ type: Output }]
    }; }
};
