    Component({
        selector: 'pf-radio',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    <label class="ds-choice" [attr.data-disabled]="effectiveDisabled ? 'true' : null">
      <input
        type="radio"
        class="ds-radio"
        [id]="inputId"
        [name]="effectiveName"
        [value]="value"
        [checked]="effectiveChecked"
        [disabled]="effectiveDisabled"
        [attr.aria-invalid]="effectiveInvalid ? 'true' : null"
        [attr.aria-describedby]="hintId"
        (change)="onChange($event)"
      />
      @if (label || hint) {
        <span class="ds-choice__label">
          {{ label }}
          @if (hint) {
            <span [attr.id]="hintId" class="ds-choice__hint">{{ hint }}</span>
          }
        </span>
      }
    </label>
  `,
    })
